css:
.loader {color: var(--loader-color, #e11d48);
  --loader-secondary-color: #fb7185;
  --loader-bg: #ffffff;
  width: 50px;
  aspect-ratio: 1;
  display: grid;
}.loader::before,.loader::after {content: "";
  grid-area: 1/1;
  border-radius: 50%;
  background: repeating-radial-gradient(farthest-side,#0000 0%,currentColor 1% 10%,#0000 11% 30%);
  -webkit-mask: repeating-conic-gradient(currentColor 0 36deg,#0000 0 72deg);
  animation: l19 4s infinite linear;
}.loader::after {-webkit-mask: repeating-conic-gradient(#0000 0 36deg,currentColor 0 72deg);
  animation-direction: reverse;
}@keyframes l19 {100% {transform: rotate(1turn)}}
